const items = $input.all();
const validItems = items.filter(item => item.json.fields !== undefined);
const isReturning = validItems.length > 0;

let conversationHistory = 'None \u2014 this is a first-time contact.';
let priorCategory = null;
let shouldGreet = true; // default: greet a first-time contact

if (isReturning) {
  const sorted = [...validItems].sort((a, b) => {
    return new Date(a.json.createdTime) - new Date(b.json.createdTime);
  });

  conversationHistory = sorted.map(item => {
    const f = item.json.fields;
    const when = item.json.createdTime ? new Date(item.json.createdTime).toLocaleString() : 'unknown time';
    return '[' + when + '] Customer said: \"' + (f.Message || '') + '\" (categorized ' + (f.Category || 'n/a') + ')';
  }).join('\n');

  priorCategory = sorted[sorted.length - 1].json.fields.Category || null;

  const lastContactTime = new Date(sorted[sorted.length - 1].json.createdTime);
  const now = new Date();
  const hoursSinceLastContact = (now - lastContactTime) / (1000 * 60 * 60);
  shouldGreet = hoursSinceLastContact >= 3;
}

return [{
  json: {
    is_returning_contact: isReturning,
    prior_category: priorCategory,
    conversation_history: conversationHistory,
    should_greet: shouldGreet
  }
}];

